import React from 'react'
import styles from './styles.module.css'
import { Link, NavLink } from 'react-router-dom';

export default function csharp() {
    return (
        <div className="container">
            <h1 className={styles.title}>C#</h1>
            <h5 className={styles.subtitle}>Examples and projects</h5>
            <hr />

            <h2 className={styles.category}>.NET Libraries</h2>
            <ul>
                <li>
                    <h5><a href="https://github.com/ryankueter/c-sharp-task-examples" target="_blank">Task Parallel Library (TPL)</a></h5>
                    <p>TPL Examples written in .NET Core 3.0</p>
                </li>
                <li>
                    <h5><a href="https://github.com/ryankueter/c-sharp-httpclient-examples" target="_blank">HttpClient Library</a></h5>
                    <p>A project that demonstrates how to use the HttpClient (.NET Framework 4.6).</p>
                </li>
                <li>
                    <h5><a href="https://github.com/ryankueter/c-sharp-concurrent-collection-examples" target="_blank">Concurrent Collections</a></h5>
                    <p>Examples of how to use the built-in concurrent collections.</p>
                </li>
                <li>
                    <h5><a href="https://github.com/ryankueter/c-sharp-filesystem-watcher-example" target="_blank">Filesystem Watcher</a></h5>
                    <p>Examples of how to use filesystem watcher.</p>
                </li>
            </ul>

            <h2 className={styles.category}>Projects</h2>
            <ul>
                <li>
                    <h5><a href="https://github.com/ryankueter/c-sharp-wmi" target="_blank">Windows Management Instrumentation (WMI) Queries</a></h5>
                    <p>A library of Windows Management Instrumentation (WMI) queries.</p>
                </li>
                <li>
                    <h5><a href="https://github.com/ryankueter/c-sharp-sockets-network-stream-example" target="_blank">Sockets Network Stream Example</a></h5>
                    <p>A Client/Server NetworkStream application written in .NET 4.5.</p>
                </li>
                <li>
                    <h5><a href="https://github.com/ryankueter/c-sharp-ad-examples" target="_blank">Active Directory</a></h5>
                    <p>Active Directory examples translated from VB.NET.</p>
                </li>
                <li>
                    <h5><a href="https://github.com/ryankueter/c-sharp-verboslog" target="_blank">VerbosLog</a></h5>
                    <p>A simple event logger with verbosity, which makes it easier to debug service type applications.</p>
                </li>
            </ul>

            <h2 className={styles.category}>Third Party</h2>
            <ul>
                <li>
                    <h5><a href="https://github.com/ryankueter/c-sharp-compression-examples" target="_blank">File Compression</a></h5>
                    <p>Examples of how to use compression libraries, like IO.Compression, ICSharp, and IonicZip.</p>
                </li>
                <li>
                    <h5><a href="https://github.com/ryankueter/c-sharp-winscp-interop" target="_blank">WinSCP Interop</a></h5>
                    <p>An old WinSCP Interop example used to sign-in to secure FTP and update files.</p>
                </li>
            </ul>
        </div>
    )
}
