import React from 'react'
import Navbar from 'react-bootstrap/Navbar'
import Nav from 'react-bootstrap/Nav'
import NavDropdown from 'react-bootstrap/NavDropdown'
import { Link, NavLink } from 'react-router-dom';

const linkStyle = {
    textDecoration: 'none',
}

function navbar() {
    return (
        <Navbar bg="light" expand="lg">
            <Navbar.Brand><Link style={linkStyle} to="/">Ryan Kueter</Link></Navbar.Brand>
            <Navbar.Toggle aria-controls="basic-navbar-nav" />
            <Navbar.Collapse id="basic-navbar-nav">
                <Nav className="mr-auto">
                    <NavDropdown title="Programming" id="basic-nav-dropdown">
                        
                        <NavDropdown.Item as={NavLink} to='/c-sharp' exact>C#</NavDropdown.Item>
                        <NavDropdown.Item as={NavLink} to='/php' exact>PHP</NavDropdown.Item>
                    </NavDropdown>
                    <NavDropdown title="Infrastructure" id="basic-nav-dropdown">
                        <NavDropdown.Item as={NavLink} to='/windows' exact>Windows</NavDropdown.Item>
                        <NavDropdown.Item as={NavLink} to='/linux' exact>Linux</NavDropdown.Item>
                    </NavDropdown>
                </Nav>
            </Navbar.Collapse>
        </Navbar>
    )
}

export default React.memo(navbar)
